import { useRef } from "react";
import hereImg from "../assets/Hero.jpg";
const HERO_IMAGE = "data:image/jpeg;base64,";

const style = `
  @import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@700;800;900&family=Barlow:wght@300;400;500&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  .hero-root {
    position: relative;
    width: 100%;
    height: 100svh;
    min-height: 560px;
    overflow: hidden;
    background: #1a1a1a;
    font-family: 'Barlow', sans-serif;
    -webkit-tap-highlight-color: transparent;
  }

  /* ── BACKGROUND IMAGE ── */
  .hero-bg {
    position: absolute;
    inset: 0;
    z-index: 1;
    overflow: hidden;
  }

  .hero-bg img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    object-position: center top;
    display: block;
    opacity: 0;
    animation: bgReveal 1.1s cubic-bezier(0.16, 1, 0.3, 1) 0.1s forwards;
    transition: transform 6s ease;
    will-change: transform;
  }

  .hero-root:hover .hero-bg img {
    transform: scale(1.03);
  }

  @keyframes bgReveal {
    from { opacity: 0; transform: scale(1.06); }
    to   { opacity: 1; transform: scale(1); }
  }

  /* Subtle vertical centre divider matching the original photo's gap */
  .hero-divider {
    position: absolute;
    top: 0; left: 50%;
    transform: translateX(-50%);
    width: 1px;
    height: 0;
    background: rgba(255,255,255,0.20);
    z-index: 5;
    animation: divGrow 0.8s 0.7s ease forwards;
  }
  @keyframes divGrow { to { height: 100%; } }

  /* ── OVERLAY ── */
  .hero-overlay {
    position: absolute;
    inset: 0;
    z-index: 4;
    background:
      linear-gradient(to bottom,
        rgba(0,0,0,0.10) 0%,
        rgba(0,0,0,0.32) 35%,
        rgba(0,0,0,0.42) 65%,
        rgba(0,0,0,0.55) 100%
      );
  }

  /* ── CONTENT ── */
  .hero-content {
    position: absolute;
    inset: 0;
    z-index: 10;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding-top: 40px;
    text-align: center;
    color: #fff;
  }

  .hero-title {
    font-family: 'Barlow Condensed', sans-serif;
    font-weight: 900;
    font-size: clamp(44px, 8vw, 120px);
    line-height: 0.92;
    letter-spacing: -0.01em;
    text-transform: uppercase;
    color: #ffffff;
    text-shadow: 0 4px 48px rgba(0,0,0,0.30);
    margin: 0;
    overflow: hidden;
  }

  .hero-title-line {
    display: block;
    transform: translateY(110%);
    animation: slideUp 0.9s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  }

  .hero-title-line:nth-child(1) { animation-delay: 0.55s; }
  .hero-title-line:nth-child(2) { animation-delay: 0.70s; }

  @keyframes slideUp { to { transform: translateY(0); } }

  .hero-subtitle {
    font-family: 'Barlow', sans-serif;
    font-size: clamp(14px, 1.5vw, 18px);
    font-weight: 400;
    color: rgba(255,255,255,0.82);
    letter-spacing: 0.02em;
    margin-top: 16px;
    max-width: 560px;
    line-height: 1.7;
    opacity: 0;
    transform: translateY(16px);
    animation: fadeUp 0.8s 1.1s ease forwards;
  }

  @keyframes fadeUp { to { opacity: 1; transform: translateY(0); } }

  .hero-cta {
    margin-top: 24px;
    opacity: 0;
    transform: translateY(16px);
    animation: fadeUp 0.8s 1.3s ease forwards;
  }

  .btn-shop {
    display: inline-block;
    padding: 0;
    background: #ffffff;
    color: #111111;
    border: none;
    cursor: pointer;
    font-family: 'Barlow Condensed', sans-serif;
    font-size: 13px;
    font-weight: 700;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    position: relative;
    overflow: hidden;
    transition: color 0.4s ease;
  }

  .btn-shop-label {
    display: block;
    padding: 16px 56px;
    position: relative;
    z-index: 1;
    transition: color 0.4s ease;
  }

  .btn-shop::before {
    content: '';
    position: absolute;
    inset: 0;
    background: #111111;
    transform: scaleX(0);
    transform-origin: left;
    transition: transform 0.42s cubic-bezier(0.76, 0, 0.24, 1);
  }

  .btn-shop:hover { color: #ffffff; }
  .btn-shop:hover::before { transform: scaleX(1); }

  /* ── SCROLL HINT ── */
  .scroll-hint {
    position: absolute;
    bottom: 28px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 10;
    display: flex;
    flex-direction: column;
    align-items: center;
    opacity: 0;
    animation: fadeUp 0.8s 1.9s ease forwards;
    cursor: pointer;
  }

  .scroll-hint-line {
    width: 1px;
    height: 38px;
    background: linear-gradient(to bottom, rgba(255,255,255,0.55), transparent);
    animation: scrollPulse 2.2s 2.2s ease-in-out infinite;
  }

  @keyframes scrollPulse {
    0%,100% { transform: scaleY(1); opacity: 0.5; }
    50%      { transform: scaleY(1.3); opacity: 1; }
  }

  /* ── RESPONSIVE ── */
  @media (max-width: 768px) {
    .hero-content { padding-bottom: 60px; }
    .hero-subtitle { font-size: 14px; padding: 0 24px; }
    .btn-shop-label { padding: 14px 40px; }
  }

  @media (max-width: 480px) {
    .hero-content { padding-bottom: 48px; }
    .hero-title { font-size: clamp(40px, 13vw, 72px); }
    .hero-subtitle { font-size: 13px; padding: 0 20px; margin-top: 14px; }
    .hero-cta { margin-top: 26px; }
    .btn-shop-label { padding: 13px 32px; letter-spacing: 0.14em; }
    .scroll-hint { display: none; }
  }

  @media (max-width: 380px) {
    .hero-title { font-size: clamp(34px, 13vw, 56px); }
  }

  @media (max-height: 500px) and (orientation: landscape) {
    .hero-content { padding-bottom: 28px; }
    .hero-title { font-size: clamp(32px, 8vw, 64px); }
    .hero-subtitle { display: none; }
    .scroll-hint { display: none; }
  }
`;

export default function Hero() {
  const heroRef = useRef(null);
  const scrollDown = () => window.scrollTo({ top: window.innerHeight, behavior: "smooth" });

  return (
    <>
      <style>{style}</style>
      <section className="hero-root" ref={heroRef} aria-label="Hero banner">

        {/* Background — your uploaded banner */}
        <div className="hero-bg" aria-hidden="true">
          <img src={hereImg} alt="Fashion hero banner" loading="eager" draggable="false" />
        </div>

        {/* Centre divider matching the photo's natural split */}
        <div className="hero-divider" aria-hidden="true" />

        {/* Gradient overlay */}
        <div className="hero-overlay" aria-hidden="true" />

        {/* Text content */}
        <div className="hero-content">
          <h1 className="hero-title" aria-label="Elegance In Every Stitch">
            <span className="hero-title-line">Elegance In</span>
            <span className="hero-title-line">Every Stitch</span>
          </h1>

          <p className="hero-subtitle">
            Experience timeless elegance with our carefully crafted clothing —<br />
            find your perfect blend of style and confidence.
          </p>

          <div className="hero-cta">
            <button className="btn-shop" onClick={scrollDown}>
              <span className="btn-shop-label">Shop Now</span>
            </button>
          </div>
        </div>

        {/* Scroll indicator */}
        <div
          className="scroll-hint"
          onClick={scrollDown}
          role="button"
          tabIndex={0}
          aria-label="Scroll down"
          onKeyDown={(e) => e.key === "Enter" && scrollDown()}
        >
          <div className="scroll-hint-line" />
        </div>

      </section>
    </>
  );
}